import React, { useState, useRef, useEffect } from 'react';
import { useLanguage, useTheme, useAuth } from '../App';
import { Language, Theme } from '../types';
import { LANGUAGES } from '../constants';
import { SparkleIcon, ChevronDownIcon, SunIcon, MoonIcon, UserIcon } from './icons';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  onLoginClick: () => void;
}

const Header: React.FC<HeaderProps> = ({ onLoginClick }) => {
  const { language, setLanguage, t } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const { session } = useAuth();
  const [isLangOpen, setIsLangOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLanguageChange = (lang: Language) => {
    setLanguage(lang);
    setIsLangOpen(false);
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsLangOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <header 
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 border-b ${
        isScrolled 
          ? 'bg-white/90 dark:bg-slate-900/90 backdrop-blur-md py-3 shadow-lg border-slate-200 dark:border-slate-800' 
          : 'bg-transparent py-5 border-transparent'
      }`}
    >
      <div className="container mx-auto px-6 flex justify-between items-center">
        <a href="#" className="flex items-center space-x-2 rtl:space-x-reverse group">
          <div className="bg-brand-500 p-1.5 rounded-lg group-hover:rotate-12 transition-transform duration-300 shadow-brand-500/30 shadow-lg">
            <SparkleIcon className="h-6 w-6 text-white" />
          </div>
          <span className={`text-xl font-bold tracking-tight transition-colors ${isScrolled ? 'text-slate-900 dark:text-white' : 'text-slate-900 dark:text-white sm:text-slate-900 sm:dark:text-white md:text-white'}`}>
            StaySparkling<span className="text-brand-500">.</span>
          </span>
        </a>

        <div className="flex items-center space-x-3 md:space-x-6 rtl:space-x-reverse">
          <nav className="hidden lg:flex items-center space-x-8 rtl:space-x-reverse">
            {['Home', 'Services', 'Why Us'].map((item, idx) => {
              const keys = ['navHome', 'navServices', 'navWhyUs'];
              return (
                <a 
                  key={item}
                  href={`#${item.toLowerCase().replace(' ', '-')}`} 
                  className={`text-sm font-medium hover:text-brand-500 transition-colors ${isScrolled ? 'text-slate-600 dark:text-slate-300' : 'text-slate-800 dark:text-slate-100 md:text-white/90'}`}
                >
                  {(t as any)[keys[idx]]}
                </a>
              );
            })}
          </nav>

          <div className="h-6 w-px bg-slate-200 dark:bg-slate-800 hidden sm:block"></div>

          <div className="flex items-center space-x-2 md:space-x-4 rtl:space-x-reverse">
            <div className="relative" ref={dropdownRef}>
              <button
                onClick={() => setIsLangOpen(!isLangOpen)}
                className={`flex items-center space-x-2 rtl:space-x-reverse px-2 py-1.5 rounded-full border transition-all ${
                  isScrolled 
                    ? 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800' 
                    : 'border-white/20 bg-white/10 backdrop-blur-sm'
                } hover:border-brand-500`}
              >
                <span className="text-lg leading-none" aria-label={LANGUAGES[language].nativeName}>{LANGUAGES[language].flag}</span>
                <ChevronDownIcon className={`h-3 w-3 transition-transform duration-300 ${isLangOpen ? 'rotate-180' : ''} ${isScrolled ? 'text-slate-500' : 'text-white'}`} />
              </button>
              {isLangOpen && (
                <div className="absolute end-0 mt-3 w-44 bg-white dark:bg-slate-800 rounded-xl shadow-2xl py-2 z-50 border border-slate-100 dark:border-slate-700 animate-fade-in">
                  {Object.entries(LANGUAGES).map(([langCode, { nativeName, flag }]) => (
                    <button
                      key={langCode}
                      onClick={() => handleLanguageChange(langCode as Language)}
                      className="w-full flex items-center space-x-3 rtl:space-x-reverse text-start px-4 py-2.5 text-sm text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                    >
                      <span className="text-lg">{flag}</span>
                      <span className="font-medium">{nativeName}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <button 
              onClick={toggleTheme} 
              className={`p-2 rounded-full transition-all hover:bg-brand-500/10 hover:text-brand-500 ${isScrolled ? 'text-slate-500 dark:text-slate-400' : 'text-slate-700 dark:text-slate-100 md:text-white'}`}
            >
              {theme === Theme.LIGHT ? <MoonIcon className="h-5 w-5" /> : <SunIcon className="h-5 w-5" />}
            </button>

            {session ? (
               <button onClick={handleLogout} className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 hover:bg-red-50 dark:hover:bg-red-900/20 text-slate-700 dark:text-slate-200 hover:text-red-600 px-4 py-2 rounded-full text-sm font-semibold transition-all border border-transparent hover:border-red-200">
                   <UserIcon className="h-4 w-4" />
                   <span className="hidden sm:inline">{t.navLogout}</span>
               </button>
            ) : (
              <button onClick={onLoginClick} className="bg-brand-500 text-white hover:bg-brand-600 px-6 py-2 rounded-full text-sm font-bold transition-all shadow-lg shadow-brand-500/25 active:scale-95">
                {t.navLogin}
              </button>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useRef } from 'react';
import { useLanguage } from '../App';
import { Language } from '../types';

const images = [
  'https://images.unsplash.com/photo-1581578731548-c64695cc6952?ixlib=rb-4.0.3&auto=format&fit=crop&w=1770&q=90',
  'https://images.unsplash.com/photo-1616046229478-9901c5536a45?ixlib=rb-4.0.3&auto=format&fit=crop&w=1770&q=90',
  'https://images.unsplash.com/photo-1540518614846-7eded433c457?ixlib=rb-4.0.3&auto=format&fit=crop&w=1769&q=90',
  'https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?ixlib=rb-4.0.3&auto=format&fit=crop&w=1770&q=90',
];

const Hero: React.FC = () => {
  const { t, language } = useLanguage();
  const [currentIndex, setCurrentIndex] = useState(0);
  const [mousePosition, setMousePosition] = useState({ x: 0.5, y: 0.5 });
  const heroRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prevIndex) => (prevIndex + 1) % images.length);
    }, 6000);
    return () => clearInterval(interval);
  }, []);

  const handleMouseMove = (e: React.MouseEvent<HTMLElement>) => {
    if (heroRef.current) {
      const rect = heroRef.current.getBoundingClientRect();
      const x = (e.clientX - rect.left) / rect.width;
      const y = (e.clientY - rect.top) / rect.height;
      setMousePosition({ x, y });
    }
  };

  const panX = (mousePosition.x - 0.5) * -15;
  const panY = (mousePosition.y - 0.5) * -15;
  const isRtl = language === Language.AR;
  const sliderTranslateX = isRtl ? currentIndex * 100 : -currentIndex * 100;

  return (
    <section
      id="home"
      ref={heroRef}
      onMouseMove={handleMouseMove}
      className="relative h-[65vh] md:h-[80vh] w-full overflow-hidden text-white flex items-center justify-center pt-20"
    >
      {/* Background Slideshow */}
      <div
        className="absolute top-0 left-0 w-full h-full flex transition-transform duration-[1500ms] cubic-bezier(0.4, 0, 0.2, 1)"
        style={{ transform: `translateX(${sliderTranslateX}%)` }}
      >
        {images.map((src, index) => (
          <div key={index} className="w-full h-full flex-shrink-0 relative overflow-hidden">
            <div
              className="w-full h-full bg-cover bg-center transition-transform duration-300 ease-out"
              style={{
                backgroundImage: `url(${src})`,
                transform: `scale(1.15) translate(${panX}px, ${panY}px)`,
              }}
            />
            {/* Gradient Overlay */}
            <div className="absolute inset-0 bg-gradient-to-b from-slate-950/60 via-slate-950/40 to-slate-50 dark:to-slate-950 transition-colors duration-500"></div>
          </div>
        ))}
      </div>

      {/* Hero Content */}
      <div className="relative z-10 container mx-auto px-6 text-center">
        <div className="max-w-5xl mx-auto space-y-8">
          <div className="inline-flex items-center space-x-2 bg-white/10 backdrop-blur-md border border-white/20 px-4 py-1.5 rounded-full text-sm font-medium animate-fade-in shadow-xl">
             <span className="flex h-2 w-2 rounded-full bg-brand-500 animate-pulse"></span>
             <span>Trusted by 500+ Luxury Hosts in the UAE</span>
          </div>

          <h1 className="text-5xl md:text-8xl font-black tracking-tight leading-[1.1] animate-fade-in [text-wrap:balance]">
             {t.heroTitle.split(' ').map((word, i) => (
                <span key={i} className="inline-block" style={{ animationDelay: `${i * 100}ms` }}>
                  {word === 'Dubai’s' || word === 'Premium' ? <span className="text-brand-500">{word}</span> : word}&nbsp;
                </span>
             ))}
          </h1>

          <p className="text-xl md:text-2xl text-slate-100/90 max-w-2xl mx-auto leading-relaxed font-light animate-fade-in [text-wrap:balance]" style={{ animationDelay: '0.4s' }}>
            {t.heroSubtitle}
          </p>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4 pt-4 animate-fade-in" style={{ animationDelay: '0.6s' }}>
            <a href="#booking" className="animate-soap-bubble bg-brand-500 hover:bg-brand-600 text-white px-10 py-4 rounded-full font-bold text-lg transition-all shadow-2xl shadow-brand-500/40">
              {t.heroCta}
            </a>
            <a href="#services" className="bg-white/10 hover:bg-white/20 backdrop-blur-md border border-white/30 text-white px-10 py-4 rounded-full font-bold text-lg transition-all">
              {t.navServices}
            </a>
          </div>
        </div>
      </div>

      {/* Scroll indicator */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 animate-bounce opacity-50 hidden md:block">
        <div className="w-1 h-12 rounded-full bg-gradient-to-b from-brand-500 to-transparent"></div>
      </div>
    </section>
  );
};

export default Hero;

import React, { useState, useEffect } from 'react';
import { useLanguage, useBooking } from '../App';
import { SERVICE_TRANSLATIONS } from '../constants';
import { BookingDetails } from '../types';

const Counter: React.FC<{ label: string; value: number; onIncrease: () => void; onDecrease: () => void; }> = ({ label, value, onIncrease, onDecrease }) => (
  <div className="flex-1 group">
    <label className="block text-xs font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500 mb-2">{label}</label>
    <div className="flex items-center bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl p-1 shadow-inner group-focus-within:border-brand-500 transition-colors">
      <button 
        onClick={onDecrease} 
        className="w-10 h-10 flex items-center justify-center rounded-lg hover:bg-white dark:hover:bg-slate-800 text-slate-500 hover:text-brand-500 transition-all font-bold"
      >
        &minus;
      </button>
      <span className="flex-1 text-center font-bold text-lg text-slate-800 dark:text-slate-100">{value}</span>
      <button 
        onClick={onIncrease} 
        className="w-10 h-10 flex items-center justify-center rounded-lg hover:bg-white dark:hover:bg-slate-800 text-slate-500 hover:text-brand-500 transition-all font-bold"
      >
        &#43;
      </button>
    </div>
  </div>
);


const BookingSection: React.FC = () => {
    const { t, language } = useLanguage();
    const { startBooking } = useBooking();
    const [service, setService] = useState<BookingDetails['service']>('turnover');
    const [bedrooms, setBedrooms] = useState(1);
    const [bathrooms, setBathrooms] = useState(1);
    const [price, setPrice] = useState(0);

    const getTranslatedText = (key: string) => {
        return SERVICE_TRANSLATIONS[key]?.[language] || key;
    };

    useEffect(() => {
        const calculatePrice = () => {
            const basePrices = { turnover: 150, deep_clean: 300 };
            const perRoomPrices = { turnover: 50, deep_clean: 75 };
            const calculatedPrice = basePrices[service] + (bedrooms * perRoomPrices[service]) + (bathrooms * perRoomPrices[service]);
            setPrice(calculatedPrice);
        };
        calculatePrice();
    }, [service, bedrooms, bathrooms]);

    const handleBookNow = () => {
        startBooking({ service, bedrooms, bathrooms, price });
    };

    return (
        <section id="booking" className="relative z-30 px-6 -mt-12 md:-mt-24">
            <div className="container mx-auto">
                <div className="max-w-6xl mx-auto bg-white dark:bg-slate-800 rounded-3xl shadow-[0_32px_64px_-16px_rgba(0,0,0,0.15)] dark:shadow-2xl border border-slate-100 dark:border-slate-700 p-8 md:p-10 transition-all">
                    <div className="flex flex-col lg:flex-row items-center gap-10">
                        {/* Service Toggle */}
                        <div className="w-full lg:w-1/4">
                            <label className="block text-xs font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500 mb-3">{t.serviceType}</label>
                            <div className="p-1 bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-2xl flex">
                                <button
                                    onClick={() => setService('turnover')}
                                    className={`flex-1 py-3 px-4 text-sm font-bold rounded-xl transition-all ${service === 'turnover' ? 'bg-white dark:bg-slate-800 shadow-md text-brand-500' : 'text-slate-500 hover:text-slate-700'}`}
                                >
                                    {getTranslatedText('turnover_name').split(' ')[0]}
                                </button>
                                <button
                                    onClick={() => setService('deep_clean')}
                                    className={`flex-1 py-3 px-4 text-sm font-bold rounded-xl transition-all ${service === 'deep_clean' ? 'bg-white dark:bg-slate-800 shadow-md text-brand-500' : 'text-slate-500 hover:text-slate-700'}`}
                                >
                                    {getTranslatedText('deep_clean_name').split(' ')[0]}
                                </button>
                            </div>
                        </div>

                        {/* Counters */}
                        <div className="w-full lg:flex-1 flex flex-col sm:flex-row gap-6">
                            <Counter label={t.bedrooms} value={bedrooms} onIncrease={() => setBedrooms(v => v + 1)} onDecrease={() => setBedrooms(v => Math.max(1, v - 1))} />
                            <Counter label={t.bathrooms} value={bathrooms} onIncrease={() => setBathrooms(v => v + 1)} onDecrease={() => setBathrooms(v => Math.max(1, v - 1))} />
                        </div>

                        {/* Result & CTA */}
                        <div className="w-full lg:w-1/3 flex items-center justify-between lg:justify-end gap-8 pt-6 lg:pt-0 border-t lg:border-t-0 border-slate-100 dark:border-slate-700">
                            <div className="text-left rtl:text-right">
                                <p className="text-xs font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">{t.estimatedPrice}</p>
                                <div className="flex items-baseline gap-1">
                                    <span className="text-4xl font-black text-slate-900 dark:text-white leading-none">{price}</span>
                                    <span className="text-sm font-bold text-slate-500">AED</span>
                                </div>
                            </div>
                            <button
                                onClick={handleBookNow}
                                className="group relative overflow-hidden bg-brand-500 hover:bg-brand-600 text-white font-bold py-5 px-10 rounded-2xl shadow-xl shadow-brand-500/30 transition-all hover:-translate-y-1 active:scale-95 whitespace-nowrap"
                            >
                                <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                                <span className="relative z-10">{t.bookNow}</span>
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

export default BookingSection;

