import React, { useState, useRef, useEffect } from 'react';
import { useLanguage, useTheme, useAuth, useBooking } from '../App';
import { Language, Theme } from '../types';
import { LANGUAGES } from '../constants';
import { SparkleIcon, ChevronDownIcon, SunIcon, MoonIcon, UserIcon, MenuIcon, XIcon } from './icons';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  onLoginClick: () => void;
}

const Header: React.FC<HeaderProps> = ({ onLoginClick }) => {
  const { language, setLanguage, t } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const { session } = useAuth();
  const { setPage } = useBooking();
  const [isLangOpen, setIsLangOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLanguageChange = (lang: Language) => {
    setLanguage(lang);
    setIsLangOpen(false);
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
  }

  const handleLinkClick = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    setPage('home');
    setIsMenuOpen(false);
    setTimeout(() => {
      const element = document.getElementById(id);
      if (element) {
        const headerOffset = 80;
        const elementPosition = element.getBoundingClientRect().top;
        const offsetPosition = elementPosition + window.pageYOffset - headerOffset;
        window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
      }
    }, 100);
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsLangOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <>
      <header 
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 border-b ${
          isScrolled 
            ? 'bg-white/90 dark:bg-slate-900/90 backdrop-blur-md py-3 shadow-lg border-slate-200 dark:border-slate-800' 
            : 'bg-transparent py-5 border-transparent'
        }`}
      >
        <div className="container mx-auto px-6 flex justify-between items-center">
          <button onClick={() => setPage('home')} className="flex items-center space-x-2 rtl:space-x-reverse group">
            <div className="bg-brand-500 p-1.5 rounded-lg group-hover:rotate-12 transition-transform duration-300 shadow-brand-500/30 shadow-lg">
              <SparkleIcon className="h-6 w-6 text-white" />
            </div>
            <span className={`text-xl font-bold tracking-tight transition-colors ${isScrolled ? 'text-slate-900 dark:text-white' : 'text-slate-900 dark:text-white md:text-white'}`}>
              StaySparkling<span className="text-brand-500">.</span>
            </span>
          </button>

          <div className="flex items-center space-x-2 md:space-x-6 rtl:space-x-reverse">
            <nav className="hidden lg:flex items-center space-x-8 rtl:space-x-reverse">
              {[
                { label: t.navHome, id: 'home' },
                { label: t.navServices, id: 'services' },
                { label: t.navWhyUs, id: 'why-us' }
              ].map((item) => (
                <a 
                  key={item.id}
                  href={`#${item.id}`} 
                  onClick={(e) => handleLinkClick(e, item.id)}
                  className={`text-sm font-semibold hover:text-brand-500 transition-colors ${isScrolled ? 'text-slate-600 dark:text-slate-300' : 'text-slate-800 dark:text-slate-100 md:text-white/90'}`}
                >
                  {item.label}
                </a>
              ))}
            </nav>

            <div className="hidden lg:block h-6 w-px bg-slate-200 dark:bg-slate-800"></div>

            <div className="flex items-center space-x-2 md:space-x-4 rtl:space-x-reverse">
              <div className="relative" ref={dropdownRef}>
                <button
                  onClick={() => setIsLangOpen(!isLangOpen)}
                  className={`flex items-center space-x-2 rtl:space-x-reverse px-2 py-1.5 rounded-full border transition-all ${
                    isScrolled 
                      ? 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800' 
                      : 'border-white/20 bg-white/10 backdrop-blur-sm'
                  } hover:border-brand-500`}
                >
                  <span className="text-lg leading-none" aria-label={LANGUAGES[language].nativeName}>{LANGUAGES[language].flag}</span>
                  <ChevronDownIcon className={`h-3 w-3 transition-transform duration-300 ${isLangOpen ? 'rotate-180' : ''} ${isScrolled ? 'text-slate-500' : 'text-white'}`} />
                </button>
                {isLangOpen && (
                  <div className="absolute end-0 mt-3 w-44 bg-white dark:bg-slate-800 rounded-xl shadow-2xl py-2 z-50 border border-slate-100 dark:border-slate-700 animate-fade-in">
                    {Object.entries(LANGUAGES).map(([langCode, { nativeName, flag }]) => (
                      <button
                        key={langCode}
                        onClick={() => handleLanguageChange(langCode as Language)}
                        className="w-full flex items-center space-x-3 rtl:space-x-reverse text-start px-4 py-2.5 text-sm font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                      >
                        <span className="text-lg">{flag}</span>
                        <span>{nativeName}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>

              <button 
                onClick={toggleTheme} 
                className={`p-2 rounded-full transition-all hover:bg-brand-500/10 hover:text-brand-500 ${isScrolled ? 'text-slate-500 dark:text-slate-400' : 'text-slate-700 dark:text-slate-100 md:text-white'}`}
                aria-label="Toggle theme"
              >
                {theme === Theme.LIGHT ? <MoonIcon className="h-5 w-5" /> : <SunIcon className="h-5 w-5" />}
              </button>

              <div className="hidden sm:flex items-center space-x-2 rtl:space-x-reverse">
                {session ? (
                  <button onClick={handleLogout} className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 hover:bg-red-50 dark:hover:bg-red-900/20 text-slate-700 dark:text-slate-200 hover:text-red-600 px-4 py-2 rounded-full text-sm font-bold transition-all border border-transparent hover:border-red-200">
                      <UserIcon className="h-4 w-4" />
                      <span className="hidden md:inline">{t.navLogout}</span>
                  </button>
                ) : (
                  <button onClick={onLoginClick} className="bg-brand-500 text-white hover:bg-brand-600 px-6 py-2 rounded-full text-sm font-bold transition-all shadow-lg shadow-brand-500/25 active:scale-95">
                    {t.navLogin}
                  </button>
                )}
              </div>

              <button 
                onClick={() => setIsMenuOpen(true)}
                className={`lg:hidden p-2 rounded-lg transition-colors ${isScrolled ? 'text-slate-900 dark:text-white' : 'text-slate-900 md:text-white'}`}
              >
                <MenuIcon className="h-6 w-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile Drawer */}
      <div className={`fixed inset-0 z-[100] transition-opacity duration-300 ${isMenuOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
        <div className="absolute inset-0 bg-slate-950/50 backdrop-blur-sm" onClick={() => setIsMenuOpen(false)}></div>
        <div className={`absolute top-0 right-0 bottom-0 w-4/5 max-w-sm bg-white dark:bg-slate-900 transition-transform duration-300 ease-out shadow-2xl ${isMenuOpen ? 'translate-x-0' : 'translate-x-full'}`}>
          <div className="p-6 flex flex-col h-full">
            <div className="flex justify-between items-center mb-10">
              <span className="text-xl font-bold dark:text-white">Menu</span>
              <button onClick={() => setIsMenuOpen(false)} className="p-2 text-slate-500"><XIcon className="h-6 w-6" /></button>
            </div>

            <nav className="flex flex-col space-y-6">
              {[
                { label: t.navHome, id: 'home' },
                { label: t.navServices, id: 'services' },
                { label: t.navWhyUs, id: 'why-us' }
              ].map((item) => (
                <a 
                  key={item.id}
                  href={`#${item.id}`} 
                  onClick={(e) => handleLinkClick(e, item.id)}
                  className="text-2xl font-bold text-slate-800 dark:text-slate-100 active:text-brand-500"
                >
                  {item.label}
                </a>
              ))}
            </nav>

            <div className="mt-auto pt-10 border-t dark:border-slate-800">
              {session ? (
                <button onClick={handleLogout} className="w-full flex items-center justify-center gap-2 bg-slate-100 dark:bg-slate-800 p-4 rounded-2xl font-bold text-red-500">
                  <UserIcon className="h-5 w-5" />
                  {t.navLogout}
                </button>
              ) : (
                <button onClick={() => { setIsMenuOpen(false); onLoginClick(); }} className="w-full bg-brand-500 text-white p-4 rounded-2xl font-bold shadow-xl shadow-brand-500/30">
                  {t.navLogin}
                </button>
