const BookingPage: React.FC = () => {
  const { t, language } = useLanguage();
  const { bookingDetails, setPage } = useBooking();
  const { session, openLoginModal } = useAuth();

  const [step, setStep] = useState(1);
  const [bedrooms, setBedrooms] = useState(bookingDetails?.bedrooms ?? 1);
  const [bathrooms, setBathrooms] = useState(bookingDetails?.bathrooms ?? 1);
  const [kitchens, setKitchens] = useState(1);
  const [otherRooms, setOtherRooms] = useState(0);
  const [hours, setHours] = useState(3);
  const [professionals, setProfessionals] = useState(1);
  const [hasMaterials, setHasMaterials] = useState<boolean | null>(null);
  const [instructions, setInstructions] = useState('');
  const [selectedExtras, setSelectedExtras] = useState<AdditionalService[]>([]);
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [address, setAddress] = useState('');
  const [cardDetails, setCardDetails] = useState({ name: '', number: '', expiry: '', cvc: '' });
  const [cardBrand, setCardBrand] = useState<'visa' | 'mastercard' | 'amex' | null>(null);
  const [billingAddress, setBillingAddress] = useState({ country: '', street: '', city: '', zip: '' });
  const [locationStatus, setLocationStatus] = useState<'idle' | 'loading' | 'error'>('idle');
  const [coordinates, setCoordinates] = useState<{ lat: number; lon: number } | null>(null);

  const addressInputRef = useRef<HTMLInputElement>(null);
  const autocompleteInitialized = useRef(false);

    useEffect(() => {
        const initAutocomplete = () => {
            if (!addressInputRef.current || !window.google || !window.google.maps || !window.google.maps.places) return;
            if (autocompleteInitialized.current) return;

            const autocomplete = new window.google.maps.places.Autocomplete(addressInputRef.current, {
                componentRestrictions: { country: "ae" },
                fields: ["formatted_address", "geometry.location"],
            });

            autocomplete.addListener('place_changed', () => {
                const place = autocomplete.getPlace();
                if (place?.geometry?.location && place.formatted_address) {
                    setAddress(place.formatted_address);
                    setCoordinates({
                        lat: place.geometry.location.lat(),
                        lon: place.geometry.location.lng(),
                    });
                }
            });
            autocompleteInitialized.current = true;
        };

        if (step === 3 && !autocompleteInitialized.current) {
            initAutocomplete();
        }
    }, [step]);

  if (!bookingDetails) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] px-6 text-center">
        <p className="text-2xl font-black mb-8">Session Interrupted</p>
        <button onClick={() => setPage('home')} className="bg-brand-500 text-white font-bold py-4 px-10 rounded-2xl shadow-xl"> {t.backToHome} </button>
      </div>
    );
  }

  const getTranslatedText = (key: string) => SERVICE_TRANSLATIONS[key]?.[language] || key;
  const serviceName = getTranslatedText(bookingDetails.service === 'turnover' ? 'turnover_name' : 'deep_clean_name');
  const roomCharge = (Math.max(0, bedrooms - 1) + Math.max(0, bathrooms - 1) + Math.max(0, kitchens - 1) + Math.max(0, otherRooms - 1)) * 10;
  const basePrice = hours * professionals * HOURLY_RATE_AED;
  const extrasPrice = selectedExtras.reduce((sum, service) => sum + service.price, 0);
  const totalPrice = basePrice + extrasPrice + roomCharge;

  const handleConfirmBooking = () => {
    const action = () => {
        const message = `StaySparkling Booking:\nService: ${serviceName}\nProperty: ${bedrooms}BR/${bathrooms}BA\nDate: ${date} @ ${time}\nAddress: ${address}\nTotal: ${totalPrice} AED`;
        window.open(`https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(message)}`, '_blank');
    };
    if (session) action(); else openLoginModal(action);
  };

  const modernInputClasses = "block w-full rounded-2xl border-slate-200 bg-slate-50 py-4 px-5 text-base font-medium placeholder-slate-400 focus:outline-none focus:border-brand-500 focus:ring-4 focus:ring-brand-500/10 dark:border-slate-700 dark:bg-slate-900 dark:text-white transition-all";

  return (
    <main className="bg-slate-50 dark:bg-slate-950 min-h-screen pt-24 pb-32">
      <div className="container mx-auto px-6">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-12">

            <div className="lg:col-span-2 order-2 lg:order-1">
                <div className="bg-white dark:bg-slate-800 rounded-[40px] shadow-2xl p-6 sm:p-10 md:p-12 animate-fade-in border border-slate-100 dark:border-slate-700">
                    <ProgressBar currentStep={step} />

                    {step === 1 && (
                        <div className="space-y-10 animate-fade-in">
                            <div className="text-center md:text-left">
                                <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-2">{t.customizeService}</h2>
                                <p className="text-slate-500 font-medium">Define your property requirements for precise allocation.</p>
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                                <Counter label={t.cleaningHours} value={hours} onIncrease={() => setHours(h => h + 1)} onDecrease={() => setHours(h => Math.max(2, h - 1))}/>
                                <Counter label={t.numberOfProfessionals} value={professionals} onIncrease={() => setProfessionals(p => p + 1)} onDecrease={() => setProfessionals(p => Math.max(1, p - 1))}/>
                            </div>

                            <div className="grid grid-cols-2 md:grid-cols-4 gap-6 pt-10 border-t dark:border-slate-700">
                                <Counter label={t.bedrooms} value={bedrooms} onIncrease={() => setBedrooms(v => v + 1)} onDecrease={() => setBedrooms(v => Math.max(1, v - 1))}/>
                                <Counter label={t.bathrooms} value={bathrooms} onIncrease={() => setBathrooms(v => v + 1)} onDecrease={() => setBathrooms(v => Math.max(1, v - 1))}/>
                                <Counter label={t.kitchens} value={kitchens} onIncrease={() => setKitchens(v => v + 1)} onDecrease={() => setKitchens(v => Math.max(0, v - 1))}/>
                                <Counter label={t.otherRooms} value={otherRooms} onIncrease={() => setOtherRooms(v => v + 1)} onDecrease={() => setOtherRooms(v => Math.max(0, v - 1))}/>
                            </div>

                            <div>
                                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-4">{t.haveCleaningMaterials}</label>
                                <div className="grid grid-cols-2 gap-4">
                                    <button onClick={() => setHasMaterials(true)} className={`py-4 rounded-2xl font-bold border transition-all ${hasMaterials === true ? 'bg-brand-500 text-white border-brand-500' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700'}`}> {t.yes} </button>
                                    <button onClick={() => setHasMaterials(false)} className={`py-4 rounded-2xl font-bold border transition-all ${hasMaterials === false ? 'bg-brand-500 text-white border-brand-500' : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700'}`}> {t.no} </button>
                                </div>
                            </div>
                        </div>
                    )}

                    {step === 2 && (
                        <div className="space-y-8 animate-fade-in">
                            <h2 className="text-3xl font-black">{t.additionalServices}</h2>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                                {ADDITIONAL_SERVICES.map((service) => {
                                    const isSelected = selectedExtras.some(s => s.id === service.id);
                                    return (
                                        <button key={service.id} onClick={() => setSelectedExtras(prev => isSelected ? prev.filter(s => s.id !== service.id) : [...prev, service])} className={`text-left relative rounded-3xl overflow-hidden border-2 transition-all ${isSelected ? 'border-brand-500 bg-brand-50/10' : 'border-transparent bg-slate-50 dark:bg-slate-900'}`}>
                                            <img src={service.image} alt="" className="h-32 w-full object-cover opacity-80"/>
                                            <div className="p-5">
                                                <h3 className="font-bold mb-1">{getTranslatedText(service.nameKey)}</h3>
                                                <p className="text-xl font-black text-brand-500">{service.price} AED</p>
                                            </div>
                                            {isSelected && <div className="absolute top-4 right-4 bg-brand-500 text-white p-1 rounded-full"><CheckIcon className="w-4 h-4" /></div>}
                                        </button>
                                    )
                                })}
                            </div>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="space-y-10 animate-fade-in">
                            <h2 className="text-3xl font-black">{t.scheduleYourCleaning}</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 items-start">
                                <Calendar selectedDate={date} onDateSelect={setDate} />
                                <TimeSelector selectedTime={time} onTimeSelect={setTime} />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">{t.address}</label>
                                <div className="relative">
                                  <input ref={addressInputRef} type="text" value={address} onChange={e => setAddress(e.target.value)} placeholder={t.addressPlaceholder} className={modernInputClasses}/>
                                  <button onClick={handleConfirmBooking} className="absolute right-3 top-1/2 -translate-y-1/2 text-brand-500 hover:scale-110 transition-transform"> <CrosshairsIcon className="h-6 w-6" /> </button>
                                </div>
                            </div>
                        </div>
                    )}

                    {step === 4 && (
                        <div className="space-y-8 animate-fade-in">
                            <h2 className="text-3xl font-black">{t.paymentDetails}</h2>
                            <div className="p-8 border-2 border-brand-500 bg-brand-50/10 rounded-[32px] space-y-6">
                                <div className="flex justify-between items-center mb-6">
                                    <div className="flex items-center gap-4">
                                        <CreditCardIcon className="w-10 h-10 text-slate-600" />
                                        <span className="font-black text-xl">{t.creditCard}</span>
                                    </div>
                                    <div className="flex gap-2"> <VisaIcon /> <MastercardIcon /> </div>
                                </div>
                                <input type="text" placeholder={t.cardNamePlaceholder} className={modernInputClasses} />
                                {/* Fixed: Corrected 'props.cardNumberPlaceholder' to 't.cardNumberPlaceholder'. */}
                                <input type="text" placeholder={t.cardNumberPlaceholder} className={modernInputClasses} />
                            </div>
                        </div>
                    )}

                    {step === 5 && (
                        <div className="animate-fade-in text-center py-12 space-y-6">
                             <div className="inline-flex items-center justify-center w-20 h-20 bg-brand-500/10 text-brand-500 rounded-full mb-4"> <CheckIcon className="w-10 h-10" /> </div>
                             <h2 className="text-4xl font-black">{t.reviewYourBooking}</h2>
                             <p className="text-slate-500 max-w-md mx-auto font-medium">Our specialists will review your requirements and confirm your session shortly.</p>
                        </div>
                    )}

                    <div className="mt-12 flex justify-between items-center pt-8 border-t dark:border-slate-700">
                        <button onClick={step === 1 ? () => setPage('home') : () => setStep(s => s - 1)} className="flex items-center gap-2 text-slate-500 hover:text-slate-900 dark:hover:text-white font-bold transition-colors">
                            <ArrowLeftIcon className="w-5 h-5"/>
                            <span>{step === 1 ? t.backToHome : t.previousStep}</span>
                        </button>
                        <button 
                            onClick={step === 5 ? handleConfirmBooking : () => setStep(s => s + 1)} 
                            className="bg-brand-500 hover:bg-brand-600 text-white font-black py-4 px-10 rounded-2xl shadow-xl shadow-brand-500/20 active:scale-95 transition-all"
                        >
                            {step === 5 ? t.confirmBooking : t.nextStep}
                        </button>
                    </div>
                </div>
            </div>

            <div className="lg:col-span-1 order-1 lg:order-2">
                 <BookingSummary 
                    {...{serviceName, bedrooms, bathrooms, kitchens, otherRooms, hours, professionals, selectedExtras, basePrice, extrasPrice, roomCharge, totalPrice, date, time, address, step}}
                />
            </div>
        </div>
      </div>
    </main>
  );
};

