          <div key={index} className="w-full h-full flex-shrink-0 relative overflow-hidden">
            <div
              className="w-full h-full bg-cover bg-center"
              style={{
                backgroundImage: `url(${src})`,
                transform: `scale(1.15) translate(${panX}px, ${panY}px)`,
                transition: 'transform 0.4s ease-out'
              }}
            />
            {/* Gradient Overlay */}
            <div className="absolute inset-0 bg-gradient-to-b from-slate-950/70 via-slate-950/40 to-slate-50 dark:to-slate-950 transition-colors duration-500"></div>
          </div>
        ))}
      </div>

      {/* Hero Content */}
      <div className="relative z-10 container mx-auto px-6 text-center">
        <div className="max-w-5xl mx-auto space-y-6 md:space-y-8">
          <div className="inline-flex items-center space-x-2 bg-white/10 backdrop-blur-md border border-white/20 px-4 py-2 rounded-full text-xs sm:text-sm font-bold animate-fade-in shadow-xl">
             <span className="flex h-2 w-2 rounded-full bg-brand-500 animate-pulse"></span>
             <span className="uppercase tracking-widest">Licensed Premium Cleaning</span>
          </div>

          <h1 className="text-4xl sm:text-6xl md:text-7xl lg:text-8xl font-black tracking-tighter leading-[1.05] animate-fade-in [text-wrap:balance]">
             {heroWords.map((word, i) => (
                <span key={i} className="inline-block" style={{ animationDelay: `${i * 80}ms` }}>
                  {word === 'Dubai’s' || word === 'Premium' || word === 'تميز' ? <span className="text-brand-500">{word}</span> : word}&nbsp;
                </span>
             ))}
          </h1>

          <p className="text-lg sm:text-xl md:text-2xl text-slate-100/90 max-w-2xl mx-auto leading-relaxed font-medium animate-fade-in [text-wrap:balance]" style={{ animationDelay: '0.4s' }}>
            {t.heroSubtitle}
