const Calendar: React.FC<{ selectedDate: string; onDateSelect: (date: string) => void; }> = ({ selectedDate, onDateSelect }) => {
    const { language } = useLanguage();
    const [displayDate, setDisplayDate] = useState(new Date());
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    const year = displayDate.getFullYear();
    const month = displayDate.getMonth();
    const firstDayOfMonth = new Date(year, month, 1);
    const lastDayOfMonth = new Date(year, month + 1, 0);
    const daysInMonth = lastDayOfMonth.getDate();
    const startDayOfWeek = firstDayOfMonth.getDay(); 

    const weekdays = [...Array(7).keys()].map(i => new Date(2023, 0, i + 1).toLocaleDateString(language, { weekday: 'narrow' }));

    const days = [];
    for (let i = 0; i < startDayOfWeek; i++) {
        days.push(<div key={`empty-${i}`} className="p-2"></div>);
    }
    for (let i = 1; i <= daysInMonth; i++) {
        const date = new Date(year, month, i);
        date.setHours(0,0,0,0);
        const dateString = date.toISOString().split('T')[0];
        const isSelected = selectedDate === dateString;
        const isPast = date < today;
        days.push(
            <button
                key={i}
                disabled={isPast}
                onClick={() => onDateSelect(dateString)}
                className={`p-2 text-center rounded-xl transition-all w-10 h-10 flex items-center justify-center font-bold ${
                    isSelected ? 'bg-brand-500 text-white shadow-lg' : 
                    isPast ? 'text-slate-300 dark:text-slate-700 cursor-not-allowed' : 
                    'text-slate-700 dark:text-slate-200 hover:bg-brand-50 dark:hover:bg-slate-800'
                }`}
            >
                {i}
            </button>
        );
    }

    return (
        <div className="bg-slate-50 dark:bg-slate-900/50 p-6 rounded-3xl border border-slate-200 dark:border-slate-800">
            <div className="flex justify-between items-center mb-6">
                <button onClick={() => setDisplayDate(new Date(year, month - 1, 1))} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800">&larr;</button>
                <h4 className="font-black text-slate-800 dark:text-slate-100">{displayDate.toLocaleString(language, { month: 'long', year: 'numeric' })}</h4>
                <button onClick={() => setDisplayDate(new Date(year, month + 1, 1))} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800">&rarr;</button>
            </div>
            <div className="grid grid-cols-7 gap-1 text-center text-[10px] font-black uppercase text-slate-400 mb-4">
                {weekdays.map((day, i) => <div key={i}>{day}</div>)}
            </div>
            <div className="grid grid-cols-7 gap-1 place-items-center">
                {days}
            </div>
        </div>
    );
};

