                  <button onClick={onLoginClick} className="bg-brand-500 text-white hover:bg-brand-600 px-7 py-2.5 rounded-full text-sm font-black transition-all shadow-lg shadow-brand-500/25 active:scale-95">
                    {t.navLogin}
                  </button>
                )}
              </div>

              <button 
                onClick={() => setIsMenuOpen(true)}
                className={`lg:hidden p-2.5 rounded-xl transition-all ${
                  isScrolled 
                  ? 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white' 
                  : 'bg-white/10 backdrop-blur-sm text-slate-900 dark:text-white md:text-white'
                } hover:scale-110 active:scale-95`}
              >
                <MenuIcon className="h-6 w-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile Drawer */}
      <div className={`fixed inset-0 z-[100] transition-opacity duration-500 ${isMenuOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
        {/* Backdrop overlay */}
        <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md transition-opacity duration-500" onClick={() => setIsMenuOpen(false)}></div>

        {/* Drawer container */}
        <div className={`absolute top-0 bottom-0 w-full max-w-sm bg-white dark:bg-slate-900 transition-transform duration-500 cubic-bezier(0.4, 0, 0.2, 1) shadow-2xl overflow-hidden ${
          isRtl 
            ? (isMenuOpen ? 'translate-x-0 left-0' : '-translate-x-full left-0') 
            : (isMenuOpen ? 'translate-x-0 right-0' : 'translate-x-full right-0')
        }`}>
          {/* Decorative Background Blob */}
          <div className="absolute -top-24 -right-24 w-64 h-64 bg-brand-500/10 rounded-full blur-3xl"></div>
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-96 h-96 bg-brand-500/5 rounded-full blur-[100px] pointer-events-none"></div>

          <div className="relative p-8 flex flex-col h-full z-10">
            {/* Header of drawer */}
            <div className="flex justify-between items-center mb-12">
              <div className="flex items-center gap-3">
                 <div className="bg-brand-500 p-2 rounded-xl shadow-lg shadow-brand-500/30">
                    <SparkleIcon className="h-6 w-6 text-white" />
                 </div>
                 <span className="text-xl font-black tracking-tight dark:text-white">StaySparkling</span>
              </div>
              <button 
                onClick={() => setIsMenuOpen(false)} 
                className="p-2.5 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-all hover:rotate-90"
              >
                <XIcon className="h-6 w-6" />
              </button>
            </div>

            {/* Navigation links */}
            <nav className="flex flex-col space-y-2">
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-4 ps-1">Menu Concierge</p>
              {[
                { label: t.navHome, id: 'home' },
                { label: t.navServices, id: 'services' },
                { label: t.navWhyUs, id: 'why-us' }
              ].map((item) => (
                <a 
                  key={item.id}
                  href={`#${item.id}`} 
                  onClick={(e) => handleLinkClick(e, item.id)}
                  className="group flex items-center justify-between p-4 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-700"
                >
                  <span className="text-2xl font-black text-slate-800 dark:text-slate-100 group-hover:text-brand-500 transition-colors">
                    {item.label}
                  </span>
                  <div className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all -translate-x-2 group-hover:translate-x-0 rtl:translate-x-2 rtl:group-hover:translate-x-0">
                    <span className="text-brand-500 text-lg">→</span>
                  </div>
                </a>
              ))}
            </nav>

            {/* Bottom Actions */}
            <div className="mt-auto space-y-4 pt-8 border-t border-slate-100 dark:border-slate-800">
              <div className="flex items-center justify-between mb-4">
                 <div className="flex items-center gap-2">
                    <button 
                      onClick={toggleTheme} 
                      className="p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl text-slate-600 dark:text-slate-300"
                    >
                      {theme === Theme.LIGHT ? <MoonIcon className="h-6 w-6" /> : <SunIcon className="h-6 w-6" />}
                    </button>
                    <div className="relative">
                       {/* Language selector for mobile drawer could be added here if needed, 
                           but keeping it simple with buttons for EN/AR is often better */}
                       <div className="flex gap-1 p-1 bg-slate-100 dark:bg-slate-800 rounded-2xl">
                          {Object.entries(LANGUAGES).map(([code, data]) => (
                            <button 
                              key={code}
                              onClick={() => setLanguage(code as Language)}
                              className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                                language === code 
                                ? 'bg-white dark:bg-slate-700 shadow-sm text-brand-500' 
                                : 'text-slate-500'
                              }`}
                            >
                              {data.flag}
                            </button>
                          ))}
                       </div>
                    </div>
                 </div>
              </div>

              {session ? (
                <button 
                  onClick={handleLogout} 
                  className="w-full flex items-center justify-center gap-3 bg-slate-50 dark:bg-slate-800 hover:bg-red-50 dark:hover:bg-red-900/10 p-5 rounded-[2rem] font-black text-red-500 transition-all border border-slate-100 dark:border-slate-700"
                >
                  <UserIcon className="h-5 w-5" />
                  {t.navLogout}
                </button>
              ) : (
                <button 
                  onClick={() => { setIsMenuOpen(false); onLoginClick(); }} 
                  className="w-full bg-brand-500 hover:bg-brand-600 text-white p-5 rounded-[2rem] font-black text-lg shadow-xl shadow-brand-500/20 active:scale-95 transition-all flex items-center justify-center gap-3"
                >
                  <UserIcon className="h-5 w-5" />
                  {t.navLogin}
                </button>
              )}

              <p className="text-center text-[10px] text-slate-400 dark:text-slate-600 font-bold uppercase tracking-widest pt-4">
                 StaySparkling Concierge UAE
              </p>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Header;

