import React, { useState, useEffect, useRef } from 'react';
import { useLanguage } from '../App';
import { Language } from '../types';

const images = [
  'https://images.unsplash.com/photo-1581578731548-c64695cc6952?ixlib=rb-4.0.3&auto=format&fit=crop&w=1770&q=90',
  'https://images.unsplash.com/photo-1616046229478-9901c5536a45?ixlib=rb-4.0.3&auto=format&fit=crop&w=1770&q=90',
  'https://images.unsplash.com/photo-1540518614846-7eded433c457?ixlib=rb-4.0.3&auto=format&fit=crop&w=1769&q=90',
  'https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?ixlib=rb-4.0.3&auto=format&fit=crop&w=1770&q=90',
];

const Hero: React.FC = () => {
  const { t, language } = useLanguage();
  const [currentIndex, setCurrentIndex] = useState(0);
  const [mousePosition, setMousePosition] = useState({ x: 0.5, y: 0.5 });
  const heroRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prevIndex) => (prevIndex + 1) % images.length);
    }, 6000);
    return () => clearInterval(interval);
  }, []);

  const handleMouseMove = (e: React.MouseEvent<HTMLElement>) => {
    if (heroRef.current) {
      const rect = heroRef.current.getBoundingClientRect();
      const x = (e.clientX - rect.left) / rect.width;
      const y = (e.clientY - rect.top) / rect.height;
      setMousePosition({ x, y });
    }
  };

  const panX = (mousePosition.x - 0.5) * -15;
  const panY = (mousePosition.y - 0.5) * -15;
  const isRtl = language === Language.AR;
  const sliderTranslateX = isRtl ? currentIndex * 100 : -currentIndex * 100;

  // Defensive check for heroTitle to prevent splitting errors if translation is missing
  const heroWords = (t.heroTitle || '').split(' ');

  return (
    <section
      id="home"
      ref={heroRef}
      onMouseMove={handleMouseMove}
      className="relative min-h-[750px] lg:h-[85vh] w-full overflow-hidden text-white flex items-center justify-center pt-24 pb-32"
    >
      {/* Background Slideshow */}
      <div
        className="absolute top-0 left-0 w-full h-full flex transition-transform duration-[1500ms] ease-in-out"
        style={{ transform: `translateX(${sliderTranslateX}%)` }}
      >
        {images.map((src, index) => (
          <div key={index} className="w-full h-full flex-shrink-0 relative overflow-hidden">
            <div
              className="w-full h-full bg-cover bg-center"
              style={{
                backgroundImage: `url(${src})`,
                transform: `scale(1.15) translate(${panX}px, ${panY}px)`,
                transition: 'transform 0.4s ease-out'
              }}
            />
            {/* Gradient Overlay */}
            <div className="absolute inset-0 bg-gradient-to-b from-slate-950/80 via-slate-950/40 to-slate-50 dark:to-slate-950 transition-colors duration-500"></div>
          </div>
        ))}
      </div>

      {/* Hero Content */}
      <div className="relative z-10 container mx-auto px-6 text-center">
        <div className="max-w-5xl mx-auto space-y-8 md:space-y-10">
          <div className="inline-flex items-center space-x-2 bg-white/10 backdrop-blur-md border border-white/20 px-4 py-2 rounded-full text-xs sm:text-sm font-bold animate-fade-in shadow-xl">
             <span className="flex h-2 w-2 rounded-full bg-brand-500 animate-pulse"></span>
             <span className="uppercase tracking-widest">{isRtl ? 'تنظيف متميز معتمد' : 'Licensed Premium Cleaning'}</span>
          </div>

          <h1 className="text-4xl sm:text-6xl md:text-7xl lg:text-8xl font-black tracking-tighter leading-[1.05] animate-fade-in [text-wrap:balance]">
             {heroWords.map((word, i) => {
                const isHighlighted = word === 'Dubai’s' || word === 'Premium' || word === 'تميز' || word === 'دبي';
                return (
                  <span key={i} className="inline-block" style={{ animationDelay: `${i * 80}ms` }}>
                    {isHighlighted ? <span className="text-brand-500">{word}</span> : word}&nbsp;
                  </span>
                );
             })}
          </h1>

          <p className="text-lg sm:text-xl md:text-2xl text-slate-100/90 max-w-2xl mx-auto leading-relaxed font-medium animate-fade-in [text-wrap:balance]" style={{ animationDelay: '0.4s' }}>
            {t.heroSubtitle}
          </p>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-5 pt-8 animate-fade-in" style={{ animationDelay: '0.6s' }}>
            <a href="#booking" className="w-full sm:w-auto animate-soap-bubble bg-brand-500 hover:bg-brand-600 text-white px-10 py-5 rounded-2xl font-bold text-lg transition-all shadow-2xl shadow-brand-500/40 text-center ring-4 ring-brand-500/20">
              {t.heroCta}
            </a>
            <a href="#services" className="w-full sm:w-auto bg-white/10 hover:bg-white/20 backdrop-blur-md border border-white/30 text-white px-10 py-5 rounded-2xl font-bold text-lg transition-all text-center">
              {t.navServices}
            </a>
          </div>
        </div>
      </div>

      {/* Scroll indicator */}
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 animate-bounce opacity-40 hidden md:block">
        <div className="w-1 h-12 rounded-full bg-gradient-to-b from-brand-500 to-transparent"></div>
      </div>
    </section>
  );
};

export default Hero;

import React, { useState, useEffect } from 'react';
import { useLanguage, useBooking } from '../App';
