      <button 
        onClick={onDecrease} 
        className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-white dark:hover:bg-slate-800 text-slate-500 hover:text-brand-500 transition-all font-bold"
      >
        &minus;
      </button>
      <span className="flex-1 text-center font-black text-lg text-slate-800 dark:text-slate-100">{value}</span>
      <button 
        onClick={onIncrease} 
        className="w-10 h-10 flex items-center justify-center rounded-xl hover:bg-white dark:hover:bg-slate-800 text-slate-500 hover:text-brand-500 transition-all font-bold"
      >
        &#43;
      </button>
    </div>
  </div>
);


const BookingSection: React.FC = () => {
    const { t, language } = useLanguage();
    const { startBooking } = useBooking();
    const [service, setService] = useState<BookingDetails['service']>('turnover');
    const [bedrooms, setBedrooms] = useState(1);
    const [bathrooms, setBathrooms] = useState(1);
    const [price, setPrice] = useState(0);

    const getTranslatedText = (key: string) => {
        return SERVICE_TRANSLATIONS[key]?.[language] || '';
    };

    useEffect(() => {
        const calculatePrice = () => {
            const basePrices = { turnover: 150, deep_clean: 300 };
            const perRoomPrices = { turnover: 50, deep_clean: 75 };
            const calculatedPrice = basePrices[service] + (bedrooms * perRoomPrices[service]) + (bathrooms * perRoomPrices[service]);
            setPrice(calculatedPrice);
        };
        calculatePrice();
    }, [service, bedrooms, bathrooms]);

    const handleBookNow = () => {
        startBooking({ service, bedrooms, bathrooms, price });
    };

    return (
        <section id="booking" className="relative z-30 px-6 -mt-16 md:-mt-24 pb-12">
            <div className="container mx-auto">
                <div className="max-w-6xl mx-auto bg-white dark:bg-slate-800 rounded-[40px] shadow-[0_40px_80px_-20px_rgba(0,0,0,0.2)] dark:shadow-2xl border border-slate-100 dark:border-slate-700 p-8 md:p-12 transition-all">
                    <div className="grid grid-cols-1 lg:grid-cols-12 items-center gap-10">
                        {/* Service Toggle */}
                        <div className="lg:col-span-3">
                            <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-3">{t.serviceType}</label>
                            <div className="p-1.5 bg-slate-100 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-[20px] flex">
                                <button
                                    onClick={() => setService('turnover')}
                                    className={`flex-1 py-3 px-2 text-xs font-black rounded-[14px] transition-all uppercase tracking-tighter ${service === 'turnover' ? 'bg-white dark:bg-slate-800 shadow-md text-brand-500' : 'text-slate-500 hover:text-slate-700'}`}
                                >
                                    {(getTranslatedText('turnover_name') || 'Turnover').split(' ')[0]}
                                </button>
                                <button
                                    onClick={() => setService('deep_clean')}
                                    className={`flex-1 py-3 px-2 text-xs font-black rounded-[14px] transition-all uppercase tracking-tighter ${service === 'deep_clean' ? 'bg-white dark:bg-slate-800 shadow-md text-brand-500' : 'text-slate-500 hover:text-slate-700'}`}
                                >
                                    {(getTranslatedText('deep_clean_name') || 'Deep').split(' ')[0]}
                                </button>
                            </div>
                        </div>

                        {/* Counters */}
                        <div className="lg:col-span-5 flex flex-col sm:flex-row gap-6">
                            <Counter label={t.bedrooms} value={bedrooms} onIncrease={() => setBedrooms(v => v + 1)} onDecrease={() => setBedrooms(v => Math.max(1, v - 1))} />
                            <Counter label={t.bathrooms} value={bathrooms} onIncrease={() => setBathrooms(v => v + 1)} onDecrease={() => setBathrooms(v => Math.max(1, v - 1))} />
                        </div>

                        {/* Result & CTA */}
                        <div className="lg:col-span-4 flex items-center justify-between lg:justify-end gap-10 pt-6 lg:pt-0 border-t lg:border-t-0 border-slate-100 dark:border-slate-700">
                            <div className="text-left rtl:text-right">
                                <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">{t.estimatedPrice}</p>
                                <div className="flex items-baseline gap-1">
                                    <span className="text-5xl font-black text-slate-900 dark:text-white leading-none tracking-tighter">{price}</span>
                                    <span className="text-sm font-black text-slate-400">AED</span>
                                </div>
                            </div>
                            <button
                                onClick={handleBookNow}
                                className="group relative overflow-hidden bg-brand-500 hover:bg-brand-600 text-white font-black py-6 px-10 rounded-[2rem] shadow-2xl shadow-brand-500/40 transition-all hover:-translate-y-1 active:scale-95 whitespace-nowrap text-lg"
                            >
                                <div className="absolute inset-0 bg-gradient-to-tr from-white/10 to-transparent translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
                                <span className="relative z-10">{t.bookNow}</span>
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </section>
    );
};

