              <SparkleIcon className="h-6 w-6 text-white" />
            </div>
            <span className={`text-xl font-black tracking-tighter transition-colors ${isScrolled ? 'text-slate-900 dark:text-white' : 'text-slate-900 dark:text-white md:text-white'}`}>
              NeatoCleaning<span className="text-brand-500">.</span>
            </span>
          </button>

          <div className="flex items-center space-x-2 md:space-x-6 rtl:space-x-reverse">
            <nav className="hidden lg:flex items-center space-x-8 rtl:space-x-reverse">
              {[
