              </div>
              {index < steps.length - 1 && (
                <div className={`flex-1 h-0.5 mx-1 sm:mx-2 min-w-[20px] transition-colors duration-300 ${stepNumber < currentStep ? 'bg-brand-500' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
              )}
