  const handleConfirmBooking = () => {
    const action = () => {
        const message = `NeatoCleaning Booking:\nService: ${serviceName}\nProperty: ${bedrooms}BR/${bathrooms}BA\nDate: ${date} @ ${time}\nAddress: ${address}\nTotal: ${totalPrice} AED`;
