                                        </button>
                                    )
                                })}
                            </div>
                        </div>
                    )}

                    {step === 3 && (
                        <div className="space-y-10 animate-fade-in">
                            <h2 className="text-3xl font-black">{t.scheduleYourCleaning}</h2>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-10 items-start">
                                <Calendar selectedDate={date} onDateSelect={setDate} />
                                <TimeSelector selectedTime={time} onTimeSelect={setTime} />
                            </div>
                            <div>
                                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 mb-2">{t.address}</label>
                                <div className="relative">
                                  <input ref={addressInputRef} type="text" value={address} onChange={e => setAddress(e.target.value)} placeholder={t.addressPlaceholder} className={modernInputClasses}/>
                                  <button className="absolute right-3 rtl:left-3 rtl:right-auto top-1/2 -translate-y-1/2 text-brand-500 hover:scale-110 transition-transform"> <CrosshairsIcon className="h-6 w-6" /> </button>
                                </div>
                            </div>
                        </div>
                    )}

                    {step === 4 && (
                        <div className="space-y-8 animate-fade-in">
                            <h2 className="text-3xl font-black">{t.paymentDetails}</h2>
                            <div className="p-8 border-2 border-brand-500 bg-brand-50/10 rounded-[32px] space-y-6">
                                <div className="flex justify-between items-center mb-6">
                                    <div className="flex items-center gap-4">
                                        <CreditCardIcon className="w-10 h-10 text-slate-600" />
                                        <span className="font-black text-xl">{t.creditCard}</span>
                                    </div>
                                    <div className="flex gap-2"> <VisaIcon /> <MastercardIcon /> </div>
                                </div>
                                <input type="text" placeholder={t.cardNamePlaceholder} className={modernInputClasses} />
                                <input type="text" placeholder={t.cardNumberPlaceholder} className={modernInputClasses} />
                            </div>
                        </div>
                    )}

                    {step === 5 && (
                        <div className="animate-fade-in text-center py-12 space-y-6">
                             <div className="inline-flex items-center justify-center w-20 h-20 bg-brand-500/10 text-brand-500 rounded-full mb-4"> <CheckIcon className="w-10 h-10" /> </div>
                             <h2 className="text-4xl font-black">{t.reviewYourBooking}</h2>
                             <p className="text-slate-500 max-w-md mx-auto font-medium">{t.footerText}</p>
                        </div>
                    )}

                    <div className="mt-12 flex justify-between items-center pt-8 border-t dark:border-slate-700">
                        <button onClick={step === 1 ? () => setPage('home') : () => setStep(s => s - 1)} className="flex items-center gap-2 text-slate-500 hover:text-slate-900 dark:hover:text-white font-bold transition-colors">
                            <ArrowLeftIcon className="w-5 h-5 rtl:rotate-180"/>
                            <span>{step === 1 ? t.backToHome : t.previousStep}</span>
                        </button>
                        <button 
                            onClick={step === 5 ? handleConfirmBooking : () => setStep(s => s + 1)} 
                            className="bg-brand-500 hover:bg-brand-600 text-white font-black py-4 px-10 rounded-2xl shadow-xl shadow-brand-500/20 active:scale-95 transition-all"
                        >
                            {step === 5 ? t.confirmBooking : t.nextStep}
                        </button>
                    </div>
                </div>
            </div>

            <div className="lg:col-span-1 order-1 lg:order-2">
                 <BookingSummary 
                    {...{serviceName, bedrooms, bathrooms, kitchens, otherRooms, hours, professionals, selectedExtras, basePrice, extrasPrice, roomCharge, totalPrice, date, time, address, step}}
                />
            </div>
        </div>
      </div>
    </main>
  );
};

export default BookingPage;

