import React, { useState, useRef, useEffect } from 'react';
import { useLanguage, useTheme, useAuth, useBooking } from '../App';
import { Language, Theme } from '../types';
import { LANGUAGES } from '../constants';
import { BubblesIcon, ChevronDownIcon, SunIcon, MoonIcon, UserIcon, MenuIcon, XIcon } from './icons';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  onLoginClick: () => void;
}

const Header: React.FC<HeaderProps> = ({ onLoginClick }) => {
  const { language, setLanguage, t } = useLanguage();
  const { theme, toggleTheme } = useTheme();
  const { session } = useAuth();
  const { setPage } = useBooking();
  const [isLangOpen, setIsLangOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLanguageChange = (lang: Language) => {
    setLanguage(lang);
    setIsLangOpen(false);
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setIsMenuOpen(false);
  }

  const handleLinkClick = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    setPage('home');
    setIsMenuOpen(false);
    setTimeout(() => {
      const element = document.getElementById(id);
      if (element) {
        const headerOffset = 80;
        const elementPosition = element.getBoundingClientRect().top;
        const offsetPosition = elementPosition + window.pageYOffset - headerOffset;
        window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
      }
    }, 100);
  };

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsLangOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const isRtl = language === Language.AR;

  return (
    <>
      <header 
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 border-b ${
          isScrolled 
            ? 'bg-white/90 dark:bg-slate-900/90 backdrop-blur-xl py-3 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border-slate-200/60 dark:border-slate-800/60' 
            : 'bg-transparent py-5 border-transparent'
        }`}
      >
        <div className="container mx-auto px-6 flex justify-between items-center">
          <button onClick={() => setPage('home')} className="flex items-center space-x-2 rtl:space-x-reverse group">
            <div className="bg-brand-500 p-1.5 rounded-xl group-hover:rotate-12 transition-transform duration-300 shadow-brand-500/30 shadow-lg">
              <BubblesIcon className="h-6 w-6 text-white" />
            </div>
            <span className={`text-xl font-black tracking-tighter transition-colors ${isScrolled ? 'text-slate-900 dark:text-white' : 'text-slate-900 dark:text-white md:text-white'}`}>
              NeatoCleaning<span className="text-brand-500">.</span>
            </span>
          </button>

          <div className="flex items-center space-x-2 md:space-x-6 rtl:space-x-reverse">
            <nav className="hidden lg:flex items-center space-x-8 rtl:space-x-reverse">
              {[
                { label: t.navHome, id: 'home' },
                { label: t.navServices, id: 'services' },
                { label: t.navWhyUs, id: 'why-us' }
              ].map((item) => (
                <a 
                  key={item.id}
                  href={`#${item.id}`} 
                  onClick={(e) => handleLinkClick(e, item.id)}
                  className={`text-sm font-bold hover:text-brand-500 transition-colors ${isScrolled ? 'text-slate-600 dark:text-slate-300' : 'text-slate-800 dark:text-slate-100 md:text-white/90'}`}
                >
                  {item.label}
                </a>
              ))}
            </nav>

            <div className="hidden lg:block h-6 w-px bg-slate-200 dark:bg-slate-800"></div>

            <div className="flex items-center space-x-2 md:space-x-4 rtl:space-x-reverse">
              <div className="relative" ref={dropdownRef}>
                <button
                  onClick={() => setIsLangOpen(!isLangOpen)}
                  className={`flex items-center space-x-2 rtl:space-x-reverse px-2 py-1.5 rounded-full border transition-all ${
                    isScrolled 
                      ? 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800' 
                      : 'border-white/20 bg-white/10 backdrop-blur-sm'
                  } hover:border-brand-500`}
                >
                  <span className="text-lg leading-none" aria-label={LANGUAGES[language].nativeName}>{LANGUAGES[language].flag}</span>
                  <ChevronDownIcon className={`h-3 w-3 transition-transform duration-300 ${isLangOpen ? 'rotate-180' : ''} ${isScrolled ? 'text-slate-500' : 'text-white'}`} />
                </button>
                {isLangOpen && (
                  <div className="absolute end-0 mt-3 w-44 bg-white dark:bg-slate-800 rounded-2xl shadow-2xl py-2 z-50 border border-slate-100 dark:border-slate-700 animate-fade-in">
                    {Object.entries(LANGUAGES).map(([langCode, { nativeName, flag }]) => (
                      <button
                        key={langCode}
                        onClick={() => handleLanguageChange(langCode as Language)}
                        className="w-full flex items-center space-x-3 rtl:space-x-reverse text-start px-4 py-2.5 text-sm font-bold text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
                      >
                        <span className="text-lg">{flag}</span>
                        <span>{nativeName}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>

              <button 
                onClick={toggleTheme} 
                className={`p-2 rounded-full transition-all hover:bg-brand-500/10 hover:text-brand-500 ${isScrolled ? 'text-slate-500 dark:text-slate-400' : 'text-slate-700 dark:text-slate-100 md:text-white'}`}
                aria-label="Toggle theme"
              >
                {theme === Theme.LIGHT ? <MoonIcon className="h-5 w-5" /> : <SunIcon className="h-5 w-5" />}
              </button>

              <div className="hidden sm:flex items-center space-x-2 rtl:space-x-reverse">
                {session ? (
                  <button onClick={handleLogout} className="flex items-center gap-2 bg-slate-100 dark:bg-slate-800 hover:bg-red-50 dark:hover:bg-red-900/20 text-slate-700 dark:text-slate-200 hover:text-red-600 px-5 py-2.5 rounded-full text-sm font-black transition-all border border-transparent hover:border-red-200">
                      <UserIcon className="h-4 w-4" />
                      <span className="hidden md:inline">{t.navLogout}</span>
                  </button>
                ) : (
                  <button onClick={onLoginClick} className="bg-brand-500 text-white hover:bg-brand-600 px-7 py-2.5 rounded-full text-sm font-black transition-all shadow-lg shadow-brand-500/25 active:scale-95">
                    {t.navLogin}
                  </button>
                )}
              </div>

              <button 
                onClick={() => setIsMenuOpen(true)}
                className={`lg:hidden p-2.5 rounded-xl transition-all ${
                  isScrolled 
                  ? 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white' 
                  : 'bg-white/10 backdrop-blur-sm text-slate-900 dark:text-white md:text-white'
                } hover:scale-110 active:scale-95`}
              >
                <MenuIcon className="h-6 w-6" />
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Mobile Drawer */}
      <div className={`fixed inset-0 z-[100] transition-opacity duration-500 ${isMenuOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
        {/* Backdrop overlay */}
        <div className="absolute inset-0 bg-slate-950/40 backdrop-blur-md transition-opacity duration-500" onClick={() => setIsMenuOpen(false)}></div>

        {/* Drawer container */}
        <div className={`absolute top-0 bottom-0 w-full max-w-sm bg-white dark:bg-slate-900 transition-transform duration-500 cubic-bezier(0.4, 0, 0.2, 1) shadow-2xl overflow-hidden ${
          isRtl 
            ? (isMenuOpen ? 'translate-x-0 left-0' : '-translate-x-full left-0') 
            : (isMenuOpen ? 'translate-x-0 right-0' : 'translate-x-full right-0')
        }`}>
          {/* Decorative Background Blob */}
          <div className="absolute -top-24 -right-24 w-64 h-64 bg-brand-500/10 rounded-full blur-3xl"></div>
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-96 h-96 bg-brand-500/5 rounded-full blur-[100px] pointer-events-none"></div>

          <div className="relative p-8 flex flex-col h-full z-10">
            {/* Header of drawer */}
            <div className="flex justify-between items-center mb-12">
              <div className="flex items-center gap-3">
                 <div className="bg-brand-500 p-2 rounded-xl shadow-lg shadow-brand-500/30">
                    <BubblesIcon className="h-6 w-6 text-white" />
                 </div>
                 <span className="text-xl font-black tracking-tight dark:text-white">NeatoCleaning</span>
              </div>
              <button 
                onClick={() => setIsMenuOpen(false)} 
                className="p-2.5 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-all hover:rotate-90"
              >
                <XIcon className="h-6 w-6" />
              </button>
            </div>

            {/* Navigation links */}
            <nav className="flex flex-col space-y-2">
              <p className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-4 ps-1">Menu Concierge</p>
              {[
                { label: t.navHome, id: 'home' },
                { label: t.navServices, id: 'services' },
                { label: t.navWhyUs, id: 'why-us' }
              ].map((item) => (
                <a 
                  key={item.id}
                  href={`#${item.id}`} 
                  onClick={(e) => handleLinkClick(e, item.id)}
                  className="group flex items-center justify-between p-4 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800 transition-all border border-transparent hover:border-slate-100 dark:hover:border-slate-700"
                >
                  <span className="text-2xl font-black text-slate-800 dark:text-slate-100 group-hover:text-brand-500 transition-colors">
                    {item.label}
                  </span>
                  <div className="w-10 h-10 rounded-xl bg-slate-50 dark:bg-slate-900 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all -translate-x-2 group-hover:translate-x-0 rtl:translate-x-2 rtl:group-hover:translate-x-0">
                    <span className="text-brand-500 text-lg">→</span>
                  </div>
                </a>
              ))}
            </nav>

            {/* Bottom Actions */}
            <div className="mt-auto space-y-4 pt-8 border-t border-slate-100 dark:border-slate-800">
              <div className="flex items-center justify-between mb-4">
                 <div className="flex items-center gap-2">
                    <button 
                      onClick={toggleTheme} 
                      className="p-3 bg-slate-100 dark:bg-slate-800 rounded-2xl text-slate-600 dark:text-slate-300"
                    >
                      {theme === Theme.LIGHT ? <MoonIcon className="h-6 w-6" /> : <SunIcon className="h-6 w-6" />}
                    </button>
                    <div className="relative">
                       {/* Language selector for mobile drawer could be added here if needed, 
                           but keeping it simple with buttons for EN/AR is often better */}
                       <div className="flex gap-1 p-1 bg-slate-100 dark:bg-slate-800 rounded-2xl">
                          {Object.entries(LANGUAGES).map(([code, data]) => (
                            <button 
                              key={code}
                              onClick={() => setLanguage(code as Language)}
                              className={`px-4 py-2 rounded-xl text-sm font-bold transition-all ${
                                language === code 
                                ? 'bg-white dark:bg-slate-700 shadow-sm text-brand-500' 
                                : 'text-slate-500'
                              }`}
                            >
                              {data.flag}
                            </button>
                          ))}
                       </div>
                    </div>
                 </div>
              </div>

              {session ? (
                <button 
                  onClick={handleLogout} 
                  className="w-full flex items-center justify-center gap-3 bg-slate-50 dark:bg-slate-800 hover:bg-red-50 dark:hover:bg-red-900/10 p-5 rounded-[2rem] font-black text-red-500 transition-all border border-slate-100 dark:border-slate-700"
                >
                  <UserIcon className="h-5 w-5" />
                  {t.navLogout}
                </button>
              ) : (
                <button 
                  onClick={() => { setIsMenuOpen(false); onLoginClick(); }} 
                  className="w-full bg-brand-500 hover:bg-brand-600 text-white p-5 rounded-[2rem] font-black text-lg shadow-xl shadow-brand-500/20 active:scale-95 transition-all flex items-center justify-center gap-3"
                >
                  <UserIcon className="h-5 w-5" />
                  {t.navLogin}
                </button>
              )}

              <p className="text-center text-[10px] text-slate-400 dark:text-slate-600 font-bold uppercase tracking-widest pt-4">
                 NeatoCleaning Concierge UAE
              </p>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Header;

import React from 'react';
import { useLanguage } from '../App';
import { SERVICE_PACKAGES, SERVICE_TRANSLATIONS, WHATSAPP_NUMBER } from '../constants';
import { CheckIcon, BubblesIcon } from './icons';

const Services: React.FC = () => {
  const { language, t } = useLanguage();

  const getTranslatedText = (key: string) => {
    return SERVICE_TRANSLATIONS[key]?.[language] || key;
  };

  const whatsappUrl = `https://wa.me/${WHATSAPP_NUMBER}?text=${encodeURIComponent(t.whatsappMessage)}`;

  return (
    <section id="services" className="py-24 bg-slate-50 dark:bg-slate-950 relative overflow-hidden">
      {/* Background decoration */}
      <div className="absolute top-1/4 left-0 w-96 h-96 bg-brand-500/5 rounded-full blur-[100px] pointer-events-none"></div>

      <div className="container mx-auto px-6 relative z-10">
        <div className="max-w-3xl mx-auto text-center mb-20">
          <h2 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-white mb-6 tracking-tight">{t.servicesTitle}</h2>
          <div className="h-1.5 w-24 bg-brand-500 mx-auto rounded-full mb-6"></div>
          <p className="text-lg text-slate-500 dark:text-slate-400 font-medium">{t.servicesSubtitle}</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 items-stretch">
          {SERVICE_PACKAGES.map((pkg) => (
            <div
              key={pkg.id}
              className={`group flex flex-col rounded-[40px] shadow-2xl transition-all duration-500 hover:-translate-y-2 overflow-hidden border ${
                pkg.popular 
                  ? 'border-brand-500 ring-4 ring-brand-500/10' 
                  : 'border-slate-100 dark:border-slate-800'
              } bg-white dark:bg-slate-900`}
            >
              {pkg.popular && (
                <div className="bg-brand-500 text-white text-center py-2 text-[10px] font-black uppercase tracking-[0.2em]">
                  Most Requested Tier
                </div>
              )}

              <div className="p-10 flex flex-col flex-grow">
                <div className="flex justify-between items-start mb-6">
                  <h3 className="text-2xl font-black text-slate-900 dark:text-white tracking-tighter uppercase">{getTranslatedText(pkg.nameKey)}</h3>
                  {pkg.popular && <BubblesIcon className="h-6 w-6 text-brand-500" />}
                </div>

                <p className="text-slate-500 dark:text-slate-400 font-medium mb-8 leading-relaxed">
                  {getTranslatedText(pkg.descriptionKey)}
                </p>

                <div className="mb-10">
                  <div className="flex items-baseline gap-2">
                    <span className="text-5xl font-black text-slate-900 dark:text-white tracking-tighter">
                      {getTranslatedText(pkg.priceKey).replace(/[^\d]/g, '')}
                    </span>
                    <span className="text-sm font-black text-slate-400 uppercase tracking-widest">
                      AED {getTranslatedText(pkg.pricePeriodKey)}
                    </span>
                  </div>
                </div>

                <div className="space-y-4 mb-10 flex-grow">
                  {pkg.featuresKey.map((featureKey) => (
                    <div key={featureKey} className="flex items-start gap-3">
                      <div className="flex-shrink-0 mt-0.5">
                        <CheckIcon className="h-5 w-5 text-brand-500" />
                      </div>
                      <p className="text-sm font-bold text-slate-600 dark:text-slate-300">
                        {getTranslatedText(featureKey)}
                      </p>
                    </div>
                  ))}
                </div>

                <a
                  href={whatsappUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className={`block w-full text-center py-5 rounded-[20px] font-black text-sm uppercase tracking-widest transition-all ${
                    pkg.popular
                      ? 'bg-brand-500 text-white hover:bg-brand-600 shadow-xl shadow-brand-500/30'
                      : 'bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white hover:bg-slate-100 dark:hover:bg-slate-700'
                  }`}
                >
                  {t.getQuote}
                </a>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Services;

