                 <span className="text-xl font-black tracking-tight dark:text-white">NeatoCleaning</span>
              </div>
              <button 
                onClick={() => setIsMenuOpen(false)} 
                className="p-2.5 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-all hover:rotate-90"
              >
                <XIcon className="h-6 w-6" />
              </button>
